1	import { useQuery } from '@tanstack/react-query';
2	import { useEffect, useMemo, useState } from 'react';
3	import { useNavigate, useParams } from 'react-router-dom';
4	import { DataGrid } from '@/shared/components/DataGrid/DataGrid';
5	import { DetailPanel } from '@/shared/components/DetailPanel/DetailPanel';
6	import { getErrorPage, getSummary } from './importApi';
7	import { TERMINAL_STATUSES } from './import.model';
8	
9	const errorColumns = [
10	    { key: 'rowNo', header: '행 번호', sortable: true, width: 100 },
11	    { key: 'errorCode', header: '오류 코드', sortable: true, width: 200 },
12	    { key: 'errorMessage', header: '오류 메시지', sortable: false },
13	];
14	
15	export function DetailPage() {
16	    const navigate = useNavigate();
17	    const { historyId } = useParams();
18	    const numericHistoryId = Number(historyId);
19	    const [sort, setSort] = useState('row_no,asc');
20	    const [page, setPage] = useState(1);
21	    const [size, setSize] = useState(20);
22	    const [detailOpen, setDetailOpen] = useState(false);
23	    const [selectedRawRow, setSelectedRawRow] = useState('');
24	
25	    useEffect(() => {
26	        if (!historyId || Number.isNaN(numericHistoryId) || numericHistoryId <= 0) {
27	            navigate('/home', { replace: true });
28	        }
29	    }, [historyId, navigate, numericHistoryId]);
30	
31	    const summaryQuery = useQuery({
32	        queryKey: ['import-summary', numericHistoryId],
33	        queryFn: () => getSummary(numericHistoryId),
34	        enabled: Number.isFinite(numericHistoryId) && numericHistoryId > 0,
35	        refetchInterval: (query) => {
36	            const status = query.state.data?.history?.status;
37	            return status && TERMINAL_STATUSES.has(status) ? false : 2000;
38	        },
39	    });
40	
41	    const shouldShowErrorGrid = (summaryQuery.data?.history?.failCount ?? 0) > 0;
42	    const errorQuery = useQuery({
43	        queryKey: ['import-errors', numericHistoryId, page, size, sort],
44	        queryFn: () => getErrorPage(numericHistoryId, page, size, sort),
45	        enabled: shouldShowErrorGrid,
46	    });
47	
48	    const summary = summaryQuery.data;
49	    const isRunning = useMemo(() => {
50	        const status = summary?.history?.status;
51	        return status === 'PENDING' || status === 'RUNNING';
52	    }, [summary]);
53	
54	    if (summaryQuery.isLoading) {
55	        return <div className='rounded-2xl border border-slate-200 bg-white p-8 text-sm text-slate-600'>불러오는 중..</div>;
56	    }
57	
58	    if (!summary) {
59	        return null;
60	    }
61	
62	    return (
63	        <div className='space-y-6'>
64	            <section className='rounded-2xl border border-slate-200 bg-white p-8 shadow-sm'>
65	                <h2 className='text-2xl font-semibold text-slate-900'>가져오기 상세 #{summary.history.id}</h2>
66	                {isRunning ? <div className='mt-4 h-2 animate-pulse rounded-full bg-slate-200' /> : null}
67	                <div className='mt-5 flex flex-wrap items-center gap-3'>
68	                    <span className='rounded-full bg-slate-900 px-3 py-1 text-xs font-semibold text-white'>
69	                        {summary.history.status}
70	                    </span>
71	                    <span className='text-sm font-medium text-slate-600'>{summary.history.type}</span>
72	                </div>
73	
74	                <dl className='mt-6 grid gap-x-6 gap-y-3 text-sm text-slate-600 md:grid-cols-[160px_1fr]'>
75	                    <dt>파일명</dt>
76	                    <dd>{summary.history.fileName}</dd>
77	                    <dt>크기</dt>
78	                    <dd>{summary.history.fileSize} bytes</dd>
79	                    <dt>요청자</dt>
80	                    <dd>
81	                        {summary.history.requestedBy} ({summary.history.requestedIp})
82	                    </dd>
83	                    <dt>요청 시각</dt>
84	                    <dd>{summary.history.requestedAt}</dd>
85	                    <dt>시작 시각</dt>
86	                    <dd>{summary.history.startedAt || '-'}</dd>
87	                    <dt>종료 시각</dt>
88	                    <dd>{summary.history.endedAt || '-'}</dd>
89	                    <dt>전체 / 성공 / 실패</dt>
90	                    <dd>
91	                        {summary.history.totalCount} / {summary.history.successCount} / {summary.history.failCount}
92	                    </dd>
93	                    <dt>중복 / staging</dt>
94	                    <dd>
95	                        {summary.history.duplicateCount} / {summary.history.stagingCount}
96	                    </dd>
97	                    {summary.history.errorSummary ? (
98	                        <>
99	                            <dt>오류 요약</dt>
100	                            <dd>{summary.history.errorSummary}</dd>
101	                        </>
102	                    ) : null}
103	                </dl>
104	            </section>
105	
106	            {shouldShowErrorGrid ? (
107	                <section className='space-y-3'>
108	                    <h3 className='text-lg font-semibold text-slate-900'>오류 목록</h3>
109	                    <DataGrid
110	                        columns={errorColumns}
111	                        pageData={errorQuery.data ?? null}
112	                        onPageChange={({ page: nextPage, size: nextSize }) => {
113	                            setPage(nextPage);
114	                            setSize(nextSize);
115	                        }}
116	                        onSortChange={({ active, direction }) => {
117	                            if (!direction || (active !== 'rowNo' && active !== 'errorCode')) {
118	                                setSort('row_no,asc');
119	                                return;
120	                            }
121	
122	                            const mapped = active === 'rowNo' ? 'row_no' : 'error_code';
123	                            setSort(`${mapped},${direction}`);
124	                        }}
125	                        onRowClick={(row) => {
126	                            setSelectedRawRow(row.rawRow ?? '');
127	                            setDetailOpen(true);
128	                        }}
129	                    />
130	                    <DetailPanel
131	                        position='right'
132	                        title='원본 행'
133	                        open={detailOpen}
134	                        onOpenChange={(open) => {
135	                            setDetailOpen(open);
136	                            if (!open) {
137	                                setSelectedRawRow('');
138	                            }
139	                        }}
140	                    >
141	                        <pre className='whitespace-pre-wrap break-all text-sm text-slate-700'>{selectedRawRow}</pre>
142	                    </DetailPanel>
143	                </section>
144	            ) : null}
145	        </div>
146	    );
147	}
